class Solution:
    def mostPoints(self, questions: List[List[int]]) -> int:
        n = len(questions)
        dp = [0] * n
        for i in range(n):
            points, brainpower = questions[i]
            dp[i] = points
            for j in range(i):
                if i - j > brainpower:
                    dp[i] = max(dp[i], dp[j] + points)
        return max(dp)
